SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>1000000000.0) AND (t.Risk_Rating <= 5) AND (t.PB < 1.14) AND (t.PB > 0.1) AND (t.FSCORE >= 2.0) AND (t.NP_P0 > 0.96*t.NP_P1) AND (t.PCF>0.8) AND (t.PCF<16.0) AND (t.PE >3.2) AND (t.PE<15.0) AND ((t.NP_P0+t.NP_P1+t.NP_P2+t.NP_P3)/ NULLIF(t.OShares, 0) > 1200.0) AND (t.NP_P0/ NULLIF(t.NP_P4, 0) > 1.40) ORDER BY t.ticker, t.time